  // 转让盟主
  static async transferLeadership(req, res) {
    try {
      const { id } = req.params;
      const { new_leader_id } = req.body;
      const userId = req.user.id;

      const alliance = await Alliance.findById(id);
      if (!alliance) {
        return res.status(404).json({
          success: false,
          message: '联盟不存在'
        });
      }

      // 检查当前用户是否是盟主
      if (alliance.leader_id !== userId) {
        return res.status(403).json({
          success: false,
          message: '只有盟主可以转让盟主位置'
        });
      }

      // 检查新盟主是否是联盟成员
      const isMember = await alliance.isMember(new_leader_id);
      if (!isMember) {
        return res.status(400).json({
          success: false,
          message: '新盟主必须是联盟成员'
        });
      }

      // 更新盟主
      await db('alliances')
        .where('id', id)
        .update({ leader_id: new_leader_id });

      res.json({
        success: true,
        message: '盟主转让成功'
      });
    } catch (error) {
      console.error('转让盟主失败:', error);
      res.status(500).json({
        success: false,
        message: '转让盟主失败',
        error: error.message
      });
    }
  }

  // 任命/解除管理员
  static async updateMemberRole(req, res) {
    try {
      const { id } = req.params;
      const { member_id, role } = req.body;
      const userId = req.user.id;

      const alliance = await Alliance.findById(id);
      if (!alliance) {
        return res.status(404).json({
          success: false,
          message: '联盟不存在'
        });
      }

      // 检查当前用户权限（只有盟主可以任命/解除管理员）
      const userRole = await alliance.getUserRole(userId);
      if (userRole !== 'leader') {
        return res.status(403).json({
          success: false,
          message: '权限不足，只有盟主可以任命/解除管理员'
        });
      }

      // 检查要修改的成员是否存在
      const isMember = await alliance.isMember(member_id);
      if (!isMember) {
        return res.status(400).json({
          success: false,
          message: '该用户不是联盟成员'
        });
      }

      // 验证角色
      if (!['admin', 'member'].includes(role)) {
        return res.status(400).json({
          success: false,
          message: '无效的角色'
        });
      }

      // 不能修改盟主角色
      const memberRole = await alliance.getUserRole(member_id);
      if (memberRole === 'leader') {
        return res.status(400).json({
          success: false,
          message: '不能修改盟主角色'
        });
      }

      // 更新成员角色
      await db('alliance_members')
        .where('alliance_id', id)
        .where('user_id', member_id)
        .update({ role });

      res.json({
        success: true,
        message: `成员角色已更新为${role === 'admin' ? '管理员' : '普通成员'}`
      });
    } catch (error) {
      console.error('更新成员角色失败:', error);
      res.status(500).json({
        success: false,
        message: '更新成员角色失败',
        error: error.message
      });
    }
  }

  // 踢出联盟成员
  static async kickMember(req, res) {
    try {
      const { id } = req.params;
      const { member_id } = req.body;
      const userId = req.user.id;

      const alliance = await Alliance.findById(id);
      if (!alliance) {
        return res.status(404).json({
          success: false,
          message: '联盟不存在'
        });
      }

      // 检查当前用户权限
      const userRole = await alliance.getUserRole(userId);
      if (userRole !== 'leader' && userRole !== 'admin') {
        return res.status(403).json({
          success: false,
          message: '权限不足，只有盟主和管理员可以踢出成员'
        });
      }

      // 检查要踢出的成员是否存在
      const isMember = await alliance.isMember(member_id);
      if (!isMember) {
        return res.status(400).json({
          success: false,
          message: '该用户不是联盟成员'
        });
      }

      // 检查要踢出的成员角色
      const memberRole = await alliance.getUserRole(member_id);
      if (memberRole === 'leader') {
        return res.status(400).json({
          success: false,
          message: '不能踢出盟主'
        });
      }

      if (userRole === 'admin' && memberRole === 'admin') {
        return res.status(400).json({
          success: false,
          message: '管理员不能踢出其他管理员'
        });
      }

      // 踢出成员
      await alliance.removeMember(member_id);

      res.json({
        success: true,
        message: '成员已成功踢出'
      });
    } catch (error) {
      console.error('踢出成员失败:', error);
      res.status(500).json({
        success: false,
        message: '踢出成员失败',
        error: error.message
      });
    }
  }

