  // 申请加入联盟
  static async applyToAlliance(req, res) {
    try {
      const { id } = req.params;
      const { message } = req.body;
      const userId = req.user.id;

      const alliance = await Alliance.findById(id);
      if (!alliance) {
        return res.status(404).json({
          success: false,
          message: '联盟不存在'
        });
      }

      if (!alliance.is_public) {
        return res.status(403).json({
          success: false,
          message: '该联盟不公开，无法申请加入'
        });
      }

      // 检查用户是否已在联盟中
      const isMember = await alliance.isMember(userId);
      if (isMember) {
        return res.status(400).json({
          success: false,
          message: '您已是该联盟成员'
        });
      }

      // 检查用户是否已在其他联盟中
      const existingAlliance = await Alliance.getUserAlliance(userId);
      if (existingAlliance) {
        return res.status(400).json({
          success: false,
          message: '您已在其他联盟中，请先退出当前联盟'
        });
      }

      // 检查是否需要审批
      if (alliance.approval_required) {
        // 需要审批，创建申请记录
        await db('alliance_applications').insert({
          alliance_id: id,
          user_id: userId,
          message
        });

        res.json({
          success: true,
          message: '申请已提交，请等待审核'
        });
      } else {
        // 不需要审批，直接加入联盟
        await db('alliance_members').insert({
          alliance_id: id,
          user_id: userId,
          role: 'member',
          joined_at: db.fn.now()
        });

        // 更新联盟成员数
        await db('alliances')
          .where('id', id)
          .increment('member_count', 1);

        res.json({
          success: true,
          message: '已成功加入联盟'
        });
      }
    } catch (error) {
      console.error('申请加入联盟失败:', error);
      res.status(500).json({
        success: false,
        message: '申请加入联盟失败',
        error: error.message
      });
    }
  }

